// FOR loop - known iterations
for (int i = 0; i < 5; i++) {
    printf("%d ", i);  // 0 1 2 3 4
}

// WHILE loop - condition-based
int i = 0;
while (i < 5) {
    printf("%d ", i);
    i++;
}

// DO-WHILE loop - at least once
int j = 0;
do {
    printf("%d ", j);
    j++;
} while (j < 5);

// Print right triangle
// *
// * *
// * * *
// * * * *

for (int i = 1; i <= 4; i++) {
    for (int j = 1; j <= i; j++) {
        printf("* ");
    }
    printf("\n");
}

// Complexity: O(n^2)
